query:
SELECT psd.stationEventId, p.batchNo, COUNT(*) AS scoreRows, ROUND(SUM(psd.earnedPoints), 6) AS totalEarnedPoints, MIN(psd.createdAt) AS firstInsertedAt, MAX(psd.createdAt) AS lastInsertedAt FROM productivity_score_details psd JOIN products p ON p.id = psd.productId WHERE psd.userId = 750192 GROUP BY psd.stationEventId, p.batchNo HAVING COUNT(*) > 1 ORDER BY scoreRows DESC, psd.stationEventId LIMIT 40;

SELECT COUNT(*) AS duplicatedEventCount FROM (SELECT stationEventId FROM productivity_score_details WHERE userId = 750192 GROUP BY stationEventId HAVING COUNT(*) > 1) duplicated;

SELECT se.id AS stationEventId, se.productId, se.stationCode, se.eventType, se.operatorUserId, se.businessDate, se.createdAt, p.batchNo FROM station_events se JOIN products p ON p.id = se.productId WHERE se.operatorUserId = 750192 AND se.businessDate = '2026-05-13' AND se.stationCode = 'A1' ORDER BY se.id DESC LIMIT 100;

